class Solution:
    def numWays(self, s: str) -> int:
        MOD = 10 ** 9 + 7
        n = len(s)
        best = 0
        for i in range(1, n - 1):
            for j in range(i + 1, n):
                a, b, c = s[:i], s[i:j], s[j:]
                if a.count('1') == b.count('1') == c.count('1'):
                    best += 1
        return best % MOD

