var numWays = function(s) {
    const MOD = 1000000007;
    const n = s.length;
    let totalOnes = 0;
    for (const ch of s) if (ch === '1') totalOnes++;
    if (totalOnes % 3 !== 0) return 0;
    if (totalOnes === 0) {
        return Math.floor((n - 1) * (n - 2) / 2) % MOD;
    }
    const k = totalOnes / 3;
    const onesIdx = [];
    for (let i = 0; i < n; i++) if (s[i] === '1') onesIdx.push(i);
    const ways1 = onesIdx[k] - onesIdx[k - 1];
    const ways2 = onesIdx[2 * k] - onesIdx[2 * k - 1];
    return (ways1 * ways2) % MOD;
};
